<template>
  <div class="file-hash-tool">
    <el-card>
      <div slot="header">
        <span>文件哈希计算</span>
        <el-tag v-if="backendAvailable" type="success" size="small" style="margin-left: 10px">后端可用</el-tag>
        <el-tag v-else type="danger" size="small" style="margin-left: 10px">后端不可用</el-tag>
      </div>

      <el-row :gutter="20">
        <el-col :span="12">
          <div class="upload-area" @click="triggerUpload" @drop.prevent="handleDrop" @dragover.prevent>
            <input type="file" ref="fileInput" @change="handleFileSelect" style="display: none" />
            <div v-if="!fileInfo" class="upload-placeholder">
              <i class="el-icon-upload" style="font-size: 48px; color: #909399"></i>
              <p>点击或拖拽文件到此处</p>
              <p style="color: #909399; font-size: 12px">支持任意类型文件</p>
            </div>
            <div v-else class="file-info">
              <i class="el-icon-document" style="font-size: 48px; color: #409EFF"></i>
              <p class="filename">{{ fileInfo.filename }}</p>
              <p class="filesize">{{ fileInfo.sizeFormatted }}</p>
            </div>
          </div>

          <el-divider>哈希算法</el-divider>
          <el-radio-group v-model="algorithm" @change="calculateHash">
            <el-radio label="md5">MD5</el-radio>
            <el-radio label="sha1">SHA-1</el-radio>
            <el-radio label="sha256">SHA-256</el-radio>
            <el-radio label="sha512">SHA-512</el-radio>
          </el-radio-group>

          <div class="action-buttons">
            <el-button type="primary" @click="calculateHash" :loading="calculating" :disabled="!fileInfo || !backendAvailable">
              计算哈希
            </el-button>
            <el-button @click="clear">清空</el-button>
          </div>
        </el-col>

        <el-col :span="12">
          <el-divider>计算结果</el-divider>
          <div v-if="hashResult" class="result-area">
            <div class="result-item">
              <div class="result-label">
                <span>{{ hashResult.algorithm }} 哈希值</span>
                <el-button type="text" size="small" @click="copyHash">复制</el-button>
              </div>
              <el-input :value="hashResult.hash" readonly>
                <template slot="append">
                  <el-button @click="copyHash">复制</el-button>
                </template>
              </el-input>
            </div>

            <div class="result-item">
              <div class="result-label">文件名</div>
              <el-input :value="hashResult.filename" readonly />
            </div>

            <div class="result-item">
              <div class="result-label">文件大小</div>
              <el-input :value="formatFileSize(hashResult.size)" readonly />
            </div>

            <div class="result-item">
              <div class="result-label">计算时间</div>
              <el-input :value="hashResult.timestamp" readonly />
            </div>
          </div>
          <el-empty v-else description="请选择文件并计算哈希" :image-size="100" />

          <el-divider>历史记录</el-divider>
          <div class="history-list">
            <div v-for="(item, index) in history" :key="index" class="history-item">
              <div class="history-filename">{{ item.filename }}</div>
              <div class="history-hash">{{ item.algorithm }}: {{ item.hash.substring(0, 16) }}...</div>
            </div>
            <el-empty v-if="history.length === 0" description="暂无历史记录" :image-size="60" />
          </div>
        </el-col>
      </el-row>

      <el-divider>纯前端计算（无需后端）</el-divider>
      <el-switch v-model="useFrontend" active-text="使用前端计算" inactive-text="使用后端计算" />
      <p style="color: #909399; font-size: 12px; margin-top: 10px">
        前端计算使用Web Crypto API，支持SHA-1、SHA-256、SHA-384、SHA-512算法
      </p>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'FileHashTool',
  data() {
    return {
      fileInfo: null,
      algorithm: 'md5',
      hashResult: null,
      calculating: false,
      backendAvailable: false,
      useFrontend: false,
      history: [],
      selectedFile: null
    }
  },
  mounted() {
    this.checkBackend()
  },
  methods: {
    async checkBackend() {
      try {
        const response = await fetch('/api/ping')
        this.backendAvailable = response.ok
      } catch (e) {
        this.backendAvailable = false
      }
    },
    triggerUpload() {
      this.$refs.fileInput.click()
    },
    handleFileSelect(e) {
      const file = e.target.files[0]
      if (file) {
        this.loadFile(file)
      }
    },
    handleDrop(e) {
      const file = e.dataTransfer.files[0]
      if (file) {
        this.loadFile(file)
      }
    },
    loadFile(file) {
      this.selectedFile = file
      this.fileInfo = {
        filename: file.name,
        size: file.size,
        sizeFormatted: this.formatFileSize(file.size),
        type: file.type
      }
      this.hashResult = null
    },
    async calculateHash() {
      if (!this.selectedFile) {
        this.$message.warning('请先选择文件')
        return
      }

      this.calculating = true

      try {
        let result
        if (this.useFrontend || !this.backendAvailable) {
          result = await this.calculateFrontend()
        } else {
          result = await this.calculateBackend()
        }

        if (result) {
          this.hashResult = {
            ...result,
            timestamp: new Date().toLocaleString()
          }

          this.history.unshift({
            filename: this.fileInfo.filename,
            algorithm: this.hashResult.algorithm,
            hash: this.hashResult.hash,
            size: this.fileInfo.size,
            time: this.hashResult.timestamp
          })

          if (this.history.length > 10) {
            this.history.pop()
          }
        }
      } catch (e) {
        this.$message.error('计算失败: ' + e.message)
      } finally {
        this.calculating = false
      }
    },
    async calculateBackend() {
      const formData = new FormData()
      formData.append('file', this.selectedFile)
      formData.append('algorithm', this.algorithm)

      const response = await fetch('/api/hash/file', {
        method: 'POST',
        body: formData
      })

      const result = await response.json()

      if (result.success) {
        return {
          algorithm: result.algorithm,
          hash: result.hash,
          filename: result.filename,
          size: result.size
        }
      } else {
        throw new Error(result.error)
      }
    },
    async calculateFrontend() {
      const algorithmMap = {
        'md5': 'MD5',
        'sha1': 'SHA-1',
        'sha256': 'SHA-256',
        'sha512': 'SHA-512'
      }

      let cryptoAlgorithm = algorithmMap[this.algorithm]
      
      if (this.algorithm === 'md5') {
        this.$message.warning('Web Crypto API不支持MD5，请使用后端计算或选择其他算法')
        return null
      }

      const buffer = await this.selectedFile.arrayBuffer()
      const hashBuffer = await crypto.subtle.digest(cryptoAlgorithm, buffer)
      const hashArray = Array.from(new Uint8Array(hashBuffer))
      const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('')

      return {
        algorithm: this.algorithm.toUpperCase(),
        hash: hashHex,
        filename: this.fileInfo.filename,
        size: this.fileInfo.size
      }
    },
    copyHash() {
      if (!this.hashResult) return
      navigator.clipboard.writeText(this.hashResult.hash).then(() => {
        this.$message.success('已复制到剪贴板')
      })
    },
    formatFileSize(bytes) {
      if (bytes < 1024) return bytes + ' B'
      if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(2) + ' KB'
      if (bytes < 1024 * 1024 * 1024) return (bytes / (1024 * 1024)).toFixed(2) + ' MB'
      return (bytes / (1024 * 1024 * 1024)).toFixed(2) + ' GB'
    },
    clear() {
      this.fileInfo = null
      this.hashResult = null
      this.selectedFile = null
      this.$refs.fileInput.value = ''
    }
  }
}
</script>

<style scoped>
.file-hash-tool {
  padding: 20px;
}

.upload-area {
  border: 2px dashed #dcdfe6;
  border-radius: 8px;
  min-height: 200px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: border-color 0.3s;
}

.upload-area:hover {
  border-color: #409EFF;
}

.upload-placeholder {
  text-align: center;
  color: #909399;
}

.file-info {
  text-align: center;
}

.filename {
  font-weight: bold;
  margin-top: 10px;
  color: #303133;
}

.filesize {
  color: #909399;
  font-size: 12px;
}

.action-buttons {
  margin-top: 20px;
  text-align: center;
}

.result-area {
  background: #f5f7fa;
  border-radius: 8px;
  padding: 15px;
}

.result-item {
  margin-bottom: 15px;
}

.result-label {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 5px;
  font-weight: 500;
  color: #606266;
}

.history-list {
  max-height: 150px;
  overflow-y: auto;
}

.history-item {
  padding: 8px;
  background: #f5f7fa;
  border-radius: 4px;
  margin-bottom: 5px;
}

.history-filename {
  font-weight: 500;
  color: #303133;
}

.history-hash {
  font-family: monospace;
  font-size: 11px;
  color: #909399;
}
</style>
